148	    inline t_physical_tile_loc get_root_location(const t_physical_tile_loc& tile_loc) const {
149	        t_physical_tile_loc root_loc;
150	        root_loc.layer_num = tile_loc.layer_num;
151	        root_loc.x = tile_loc.x - get_width_offset(tile_loc);
152	        root_loc.y = tile_loc.y - get_height_offset(tile_loc);
