156	    ///@brief Returns a rectangle which represents the bounding box of the tile at the given location.
157	    inline vtr::Rect<int> get_tile_bb(const t_physical_tile_loc& tile_loc) const {
158	        t_physical_tile_type_ptr tile_type = get_physical_type(tile_loc);
159	
160	        int tile_xlow = tile_loc.x - get_width_offset(tile_loc);
161	        int tile_ylow = tile_loc.y - get_height_offset(tile_loc);
162	        int tile_xhigh = tile_xlow + tile_type->width - 1;
163	        int tile_yhigh = tile_ylow + tile_type->height - 1;
