168	    // Forward const-iterator over (layer, x, y)
169	    class loc_const_iterator {
170	      public:
171	        using value_type = t_physical_tile_loc;
172	        using difference_type = std::ptrdiff_t;
173	        using iterator_category = std::forward_iterator_tag;
174	
175	        loc_const_iterator(const DeviceGrid* g, size_t layer, size_t x, size_t y)
176	            : g_(g) {
177	            loc_.layer_num = static_cast<int>(layer);
178	            loc_.x = static_cast<int>(x);
179	            loc_.y = static_cast<int>(y);
180	        }
181	
182	        value_type operator*() const { return loc_; }
183	
184	        // pre-increment
185	        loc_const_iterator& operator++() {
186	            // advance y, then x, then layer
187	            ++loc_.y;
188	            if (loc_.y >= static_cast<int>(g_->height())) {
189	                loc_.y = 0;
190	                ++loc_.x;
191	                if (loc_.x >= static_cast<int>(g_->width())) {
192	                    loc_.x = 0;
193	                    ++loc_.layer_num;
194	                }
195	            }
196	            return *this;
197	        }
198	
199	        bool operator==(const loc_const_iterator& o) const {
200	            return loc_.x == o.loc_.x
201	                   && loc_.y == o.loc_.y
202	                   && loc_.layer_num == o.loc_.layer_num
203	                   && g_ == o.g_;
204	        }
205	        bool operator!=(const loc_const_iterator& o) const { return !(*this == o); }
206	
207	      private:
208	        const DeviceGrid* g_ = nullptr;
209	        t_physical_tile_loc loc_{0, 0, 0};
210	    };
