220	    // Forward const-iterator over all die regions in the device. See t_die_region for information on what a die region is.
221	    class die_const_iterator {
222	      public:
223	        using value_type = t_die_region;
224	        using difference_type = std::ptrdiff_t;
225	        using iterator_category = std::forward_iterator_tag;
226	
227	        die_const_iterator(const DeviceGrid* g, size_t layer, size_t x_die, size_t y_die)
228	            : g_(g) {
229	            die_region_.layer = static_cast<short>(layer);
230	            die_region_.x_die = static_cast<short>(x_die);
231	            die_region_.y_die = static_cast<short>(y_die);
232	        }
233	
234	        value_type operator*() const { return die_region_; }
235	
236	        // pre-increment
237	        die_const_iterator& operator++() {
238	            // advance x_die, then y_die, then layer
239	            ++die_region_.x_die;
240	            if (die_region_.x_die > static_cast<short>(g_->get_vertical_interposer_cuts()[die_region_.layer].size())) {
241	                die_region_.x_die = 0;
242	                ++die_region_.y_die;
243	                if (die_region_.y_die > static_cast<short>(g_->get_horizontal_interposer_cuts()[die_region_.layer].size())) {
244	                    die_region_.y_die = 0;
245	                    ++die_region_.layer;
246	                }
247	            }
248	            return *this;
249	        }
250	
251	        bool operator==(const die_const_iterator& o) const {
252	            return die_region_.x_die == o.die_region_.x_die
253	                   && die_region_.y_die == o.die_region_.y_die
254	                   && die_region_.layer == o.die_region_.layer
255	                   && g_ == o.g_;
256	        }
257	
258	        bool operator!=(const die_const_iterator& o) const { return !(*this == o); }
259	
260	      private:
261	        const DeviceGrid* g_ = nullptr;
262	        t_die_region die_region_{0, 0, 0};
263	    };
264	
265	    inline auto all_die_regions() const {
266	        return vtr::make_range(
267	            die_const_iterator(this, /*layer*/ 0, /*x*/ 0, /*y*/ 0),
268	            die_const_iterator(this, /*layer*/ get_num_layers(), /*x*/ 0, /*y*/ 0) // end sentinel
269	        );
270	    }
