272	    ///@brief Return the metadata of the tile at the specified location
273	    inline const t_metadata_dict* get_metadata(const t_physical_tile_loc& tile_loc) const {
274	        return grid_[tile_loc.layer_num][tile_loc.x][tile_loc.y].meta;
275	    }
