277	    ///@brief Given t_grid_tile, return the x coordinate of the tile on the given layer - Used by serializer functions
278	    inline int get_grid_loc_x(const t_grid_tile*& grid_loc) const {
279	        int layer_num = std::floor(static_cast<int>(grid_loc - &grid_.get(0)) / (width() * height()));
280	        auto diff = grid_loc - &grid_.get(layer_num * height() * width());
281	
282	        return diff / grid_.dim_size(2);
283	    }
284	
285	    ///@brief Given t_grid_tile, return the y coordinate of the tile on the given layer - Used by serializer functions
286	    inline int get_grid_loc_y(const t_grid_tile*& grid_loc) const {
287	        int layer_num = std::floor(static_cast<int>(grid_loc - &grid_.get(0)) / (width() * height()));
288	        auto diff = grid_loc - &grid_.get(layer_num * height() * width());
289	
290	        return diff % grid_.dim_size(2);
291	    }
292	
293	    ///@brief Given t_grid_tile, return the layer number of the tile - Used by serializer functions
294	    inline int get_grid_loc_layer(const t_grid_tile*& grid_loc) const {
295	        int layer_num = std::floor(static_cast<int>(grid_loc - &grid_.get(0)) / (width() * height()));
296	        return layer_num;
297	    }
298	
299	    ///@brief Return the nth t_grid_tile on the given layer of the flattened grid - Used by serializer functions
300	    inline const t_grid_tile* get_grid_locs_grid_loc(int n) const {
301	        return &grid_.get(n);
302	    }
