304	    /// Returns the list of horizontal interposer cut locations for each layer,
305	    /// i.e. y value of the tile row just below each cut
306	    /// Accessed as [layer][cut_idx]
307	    inline const std::vector<std::vector<int>>& get_horizontal_interposer_cuts() const {
308	        return horizontal_interposer_cuts_;
309	    }
310	
311	    /// Returns the list of vertical interposer cut locations for each layer,
312	    /// i.e. x value of the tile column just to the left each cut
313	    /// Accessed as [layer][cut_idx]
314	    inline const std::vector<std::vector<int>>& get_vertical_interposer_cuts() const {
315	        return vertical_interposer_cuts_;
316	    }
317	
318	    /// Returns if the grid has any interposer cuts. You should use this function instead of
319	    /// checking if get_horizontal/vertical_interposer_cuts is empty, since the return value
320	    /// of those functions might look something like this: {{}} which is technically not empty.
321	    bool has_interposer_cuts() const;
322	
323	    /**
324	     * @brief Returns if two locations loc_a and loc_b are on the same die, usable on 2D, 2.5D and 3D architectures.
325	     */
326	    bool are_locs_on_same_die(t_physical_tile_loc loc_a, t_physical_tile_loc loc_b) const;
327	
328	    /**
329	     * @brief Get the die identifier of a location. In 2.5D and 3D architectures each die has its own unique identifier.
330	     * 
331	     * @param loc (x, y, layer) position that you want the id of.
332	     * @return DeviceDieId ID of the given location
333	     */
334	    DeviceDieId get_loc_die_id(t_physical_tile_loc loc) const;
335	
336	    /**
337	     * @brief Get the total number of dice in the device. 2.5D and 3D architectures consist of multiple dice.
338	     */
339	    size_t get_die_count() const;
340	
341	    /**
342	     * @brief Get the die identifier of a given die region. See the comment above t_die_region for information on what a die region is.
343	     */
344	    DeviceDieId get_die_region_id(t_die_region die_region) const;
345	
346	  private:
347	    /// @brief Counts the number of each tile type on each layer and store it in instance_counts_.
348	    /// It is called in the constructor.
349	    void count_instances();
350	
351	    /**
352	     * @brief Initialize the data structures used in multi-die FPGAs, such as the die_id_matrix_ or die_region_map_.
353	     * These structures must be initialized before using are_locs_on_same_die, get_loc_die_id, get_die_count and get_die_region_id.
354	     */
355	    void initialize_multi_die_data_structures();
356	
357	    std::string name_;
358	
359	    /**
360	     * @brief grid_ is a 3D matrix that represents the grid of the FPGA chip.
361	     * @note The first dimension is the layer number (grid_[0] corresponds to the bottom layer),
362	     *       the second dimension is the x coordinate, and the third dimension is the y coordinate.
363	     * @note Note that vtr::Matrix operator[] returns and intermediate type
364	     * @note which can be used for indexing in the second dimension, allowing
365	     * @note traditional 2-d indexing to be used
366	     */
367	    vtr::NdMatrix<t_grid_tile, 3> grid_; //This stores the grid of complex blocks. It is a 3D matrix: [0..num_layers-1][0..grid.width()-1][0..grid_height()-1]
368	
369	    ///@brief instance_counts_ stores the number of each tile type on each layer. It is initialized in count_instances().
370	    std::vector<std::map<t_physical_tile_type_ptr, size_t>> instance_counts_; /* [layer_num][physical_tile_type_ptr] */
371	
372	    std::vector<t_logical_block_type_ptr> limiting_resources_;
373	
374	    /// Horizontal interposer cut locations in each layer,
375	    /// i.e. y value of the tile row just below each cut
376	    /// Accessed as [layer][cut_idx]
377	    std::vector<std::vector<int>> horizontal_interposer_cuts_;
378	    /// Vertical interposer cut location in each layer,
379	    /// i.e. x value of the tile column just to the left each cut
380	    /// Accessed as [layer][cut_idx]
381	    std::vector<std::vector<int>> vertical_interposer_cuts_;
382	
383	    /**
384	     * @brief Vector of matrices that contain a unique ID for each die of the device per grid location
385	     * For example in a 4x4 grid, if you have an interposer cut at y = 2, the matrix would look like this:
386	     * 1 1 1 1
387	     * 1 1 1 1
388	     * 0 0 0 0
389	     * 0 0 0 0
390	     *
391	     * Accessed as [layer][x][y]. die_id_matrix_[layer][x][y] returns the ID of the die at location (x, y, layer)
392	     */
393	    std::vector<vtr::NdMatrix<DeviceDieId, 2>> die_id_matrix_;
394	
395	    /// @brief Two way map between die identifiers and die regions.
396	    vtr::bimap<DeviceDieId, t_die_region> die_region_map_;
397	
398	    /// @brief True if the device has any interposer cuts. Cached for speed.
399	    bool has_interposer_cuts_;
400	
401	    /// @brief True if the grid dimensions are fixed by an externally provided RR graph.
402	    /// When set, device grid creator returns this grid unchanged rather than
403	    /// resizing from resource counts, preventing both expansion and shrinkage.
404	    bool fixed_by_rr_graph_ = false;
405	};
