96	///@brief Create the device grid based on resource requirements
97	DeviceGrid create_device_grid(const std::string& layout_name,
98	                              const std::vector<t_grid_def>& grid_layouts,
99	                              const std::map<t_logical_block_type_ptr, size_t>& minimum_instance_counts,
100	                              float target_device_utilization,
101	                              size_t fixed_device_width) {
102	    // If the grid was fixed by a read RR graph, return it unchanged to prevent resizing.
103	    if (g_vpr_ctx.device().grid.fixed_by_rr_graph()) {
104	        VTR_ASSERT(g_vpr_ctx.device().grid.width() > 0 && g_vpr_ctx.device().grid.height() > 0);
105	        return g_vpr_ctx.device().grid;
106	    }
107	
108	    if (layout_name == "auto") {
109	        // User fixed width via --device_width; derive height from <auto_layout> aspect ratio
110	        if (fixed_device_width > 0) {
111	            size_t height = compute_auto_layout_height(grid_layouts, fixed_device_width);
112	            return create_device_grid(layout_name, grid_layouts, fixed_device_width, height);
113	        }
114	        // Auto-size the device
115	        // Note that we treat the target device utilization as a maximum
116	        return auto_size_device_grid(grid_layouts, minimum_instance_counts, target_device_utilization);
117	    } else {
118	        // Use the specified device
119	
120	        // Find the matching grid definition
121	        auto cmp = [&](const t_grid_def& grid_def) {
122	            return grid_def.name == layout_name;
123	        };
124	
125	        auto iter = std::find_if(grid_layouts.begin(), grid_layouts.end(), cmp);
126	        if (iter == grid_layouts.end()) {
127	            // Not found
128	            std::string valid_names;
129	            for (size_t i = 0; i < grid_layouts.size(); ++i) {
130	                if (i != 0) {
131	                    valid_names += ", ";
132	                }
133	                valid_names += "'" + grid_layouts[i].name + "'";
134	            }
135	            VPR_FATAL_ERROR(VPR_ERROR_ARCH, "Failed to find grid layout named '%s' (valid grid layouts: %s)\n", layout_name.c_str(), valid_names.c_str());
136	        }
137	
138	        return build_device_grid(*iter, iter->width, iter->height);
139	    }
140	}
