142	///@brief Create the device grid based on dimensions
143	DeviceGrid create_device_grid(const std::string& layout_name, const std::vector<t_grid_def>& grid_layouts, size_t width, size_t height) {
144	    // If the grid was fixed by a read RR graph, return it unchanged to prevent resizing.
145	    if (g_vpr_ctx.device().grid.fixed_by_rr_graph()) {
146	        VTR_ASSERT(g_vpr_ctx.device().grid.width() > 0 && g_vpr_ctx.device().grid.height() > 0);
147	        return g_vpr_ctx.device().grid;
148	    }
149	
150	    if (layout_name == "auto") {
151	        VTR_ASSERT(!grid_layouts.empty());
152	        //Auto-size
153	        if (grid_layouts[0].grid_type == e_grid_def_type::AUTO) {
154	            //Auto layout of the specified dimensions
155	            return build_device_grid(grid_layouts[0], width, height);
156	        } else {
157	            //Find the fixed layout close to the target size
158	            std::vector<const t_grid_def*> grid_layouts_view;
159	            grid_layouts_view.reserve(grid_layouts.size());
160	            for (const t_grid_def& layout : grid_layouts) {
161	                grid_layouts_view.push_back(&layout);
162	            }
163	            auto sort_cmp = [](const t_grid_def* lhs, const t_grid_def* rhs) {
164	                return lhs->width < rhs->width || lhs->height < rhs->width;
165	            };
166	            std::stable_sort(grid_layouts_view.begin(), grid_layouts_view.end(), sort_cmp);
167	
168	            auto find_cmp = [&](const t_grid_def* grid_def) {
169	                return grid_def->width >= int(width) && grid_def->height >= int(height);
170	            };
171	            auto iter = std::find_if(grid_layouts_view.begin(), grid_layouts_view.end(), find_cmp);
172	
173	            if (iter == grid_layouts_view.end()) {
174	                //No device larger than specified width/height, so choose largest possible
175	                VTR_LOG_WARN(
176	                    "Specified device dimensions (%zux%zu) exceed those of the largest fixed-size device."
177	                    " Using the largest fixed-size device\n",
178	                    width, height);
179	                --iter;
180	            }
181	
182	            const t_grid_def* layout = *iter;
183	
184	            return build_device_grid(*layout, layout->width, layout->height);
185	        }
186	    } else {
187	        // Use the specified device
188	        auto cmp = [&](const t_grid_def& grid_def) {
189	            return grid_def.name == layout_name;
190	        };
191	
192	        auto iter = std::find_if(grid_layouts.begin(), grid_layouts.end(), cmp);
193	        if (iter == grid_layouts.end()) {
194	            //Not found
195	            std::string valid_names;
196	            for (size_t i = 0; i < grid_layouts.size(); ++i) {
197	                if (i != 0) {
198	                    valid_names += ", ";
199	                }
200	                valid_names += "'" + grid_layouts[i].name + "'";
201	            }
202	            VPR_FATAL_ERROR(VPR_ERROR_ARCH, "Failed to find grid layout named '%s' (valid grid layouts: %s)\n", layout_name.c_str(), valid_names.c_str());
203	        }
204	
205	        return build_device_grid(*iter, iter->width, iter->height);
206	    }
207	}
