209	static DeviceGrid auto_size_device_grid(const std::vector<t_grid_def>& grid_layouts,
210	                                        const std::map<t_logical_block_type_ptr, size_t>& minimum_instance_counts,
211	                                        float maximum_device_utilization) {
212	    VTR_ASSERT(!grid_layouts.empty());
213	
214	    DeviceGrid grid;
215	
216	    auto is_auto_grid_def = [](const t_grid_def& grid_def) noexcept {
217	        return grid_def.grid_type == e_grid_def_type::AUTO;
218	    };
219	
220	    auto auto_layout_itr = std::ranges::find_if(grid_layouts, is_auto_grid_def);
221	    if (auto_layout_itr != grid_layouts.end()) {
222	        //Automatic grid layout, find the smallest height/width
223	        VTR_ASSERT_SAFE_MSG(std::find_if(auto_layout_itr + 1, grid_layouts.end(), is_auto_grid_def) == grid_layouts.end(), "Only one <auto_layout>");
224	
225	        //Determine maximum device size to try before concluding that the circuit cannot fit on any device
226	        //Calculate total number of required instances
227	        //Then multiply by a factor of MAX_SIZE_FACTOR as overhead
228	        //This is to avoid infinite loop if increasing the grid size never gets you more of the instance
229	        //type you need and hence never lets you fit the design
230	        size_t max_size;
231	        size_t total_minimum_instance_counts = 0;
232	        for (auto& inst : minimum_instance_counts) {
233	            size_t count = inst.second;
234	            total_minimum_instance_counts += count;
235	        }
236	        max_size = total_minimum_instance_counts * MAX_SIZE_FACTOR;
237	
238	        const t_grid_def& grid_def = *auto_layout_itr;
239	        VTR_ASSERT(grid_def.aspect_ratio >= 0.);
240	
241	        //Initial size is num_layers x 3 x 3, the smallest possible while avoiding
242	        //start before end location issues with <perimeter> location
243	        //specifications
244	        size_t width = 3;
245	        size_t height = 3;
246	        std::vector<t_logical_block_type_ptr> limiting_resources;
247	        size_t grid_size = 0;
248	        do {
249	            //Scale opposite dimension to match aspect ratio
250	            height = vtr::nint(width / grid_def.aspect_ratio);
251	
252	#ifdef VERBOSE
253	            VTR_LOG("Grid size: %zu x %zu (AR: %.2f) \n", width, height, float(width) / height);
254	#endif
255	
256	            //Build the device
257	            // Don't warn about out-of-range specifications since these can
258	            // occur (harmlessly) at small device dimensions
259	            grid = build_device_grid(grid_def, width, height, false, limiting_resources);
260	
261	            //Check if it satisfies the block counts
262	            if (grid_satisfies_instance_counts(grid, minimum_instance_counts, maximum_device_utilization)) {
263	                //Re-build the grid at the final size with out-of-range
264	                grid = build_device_grid(grid_def, width, height, false, limiting_resources);
265	                return grid;
266	            }
267	
268	            limiting_resources = grid_overused_resources(grid, minimum_instance_counts);
269	
270	            //Determine grid size
271	            grid_size = width * height;
272	
273	            //Increase the grid size
274	            width++;
275	
276	        } while (grid_size < max_size);
277	
278	        //Maximum device size reached
279	        VPR_FATAL_ERROR(VPR_ERROR_OTHER,
280	                        "Device auto-fit aborted: device size already exceeds required resources count by %d times yet still cannot fit the design. "
281	                        "This may be due to resources that do not grow as the grid size increases (e.g. PLLs in the Titan Stratix IV architecture capture).\n",
282	                        MAX_SIZE_FACTOR);
283	
284	    } else {
285	        VTR_ASSERT(auto_layout_itr == grid_layouts.end());
286	        //Fixed grid layouts, find the smallest of the fixed layouts
287	
288	        //Sort the grid layouts from smallest to largest
289	        std::vector<const t_grid_def*> grid_layouts_view;
290	        grid_layouts_view.reserve(grid_layouts.size());
291	        for (const t_grid_def& layout : grid_layouts) {
292	            grid_layouts_view.push_back(&layout);
293	        }
294	        auto area_cmp = [](const t_grid_def* lhs, const t_grid_def* rhs) {
295	            VTR_ASSERT(lhs->grid_type == e_grid_def_type::FIXED);
296	            VTR_ASSERT(rhs->grid_type == e_grid_def_type::FIXED);
297	
298	            int lhs_area = lhs->width * lhs->height;
299	            int rhs_area = rhs->width * rhs->height;
300	
301	            return lhs_area < rhs_area;
302	        };
303	        std::stable_sort(grid_layouts_view.begin(), grid_layouts_view.end(), area_cmp);
304	
305	        std::vector<t_logical_block_type_ptr> limiting_resources;
306	
307	        //Try all the fixed devices in order from smallest to largest
308	        for (const t_grid_def* grid_def : grid_layouts_view) {
309	            //Build the grid
310	            grid = build_device_grid(*grid_def, grid_def->width, grid_def->height, true, limiting_resources);
311	
312	            if (grid_satisfies_instance_counts(grid, minimum_instance_counts, maximum_device_utilization)) {
313	                return grid;
314	            }
315	            limiting_resources = grid_overused_resources(grid, minimum_instance_counts);
316	        }
317	    }
318	
319	    return grid; //Unreachable
320	}
