322	static std::vector<t_logical_block_type_ptr> grid_overused_resources(const DeviceGrid& grid,
323	                                                                     std::map<t_logical_block_type_ptr, size_t> instance_counts) {
324	    DeviceContext& device_ctx = g_vpr_ctx.mutable_device();
325	
326	    std::vector<t_logical_block_type_ptr> overused_resources;
327	
328	    std::unordered_map<t_physical_tile_type_ptr, size_t> min_count_map;
329	    // Initialize min_count_map
330	    for (const t_physical_tile_type& tile_type : device_ctx.physical_tile_types) {
331	        min_count_map.insert(std::make_pair(&tile_type, size_t(0)));
332	    }
333	
334	    //Initialize available tile counts
335	    std::unordered_map<t_physical_tile_type_ptr, int> avail_tiles;
336	    for (const t_physical_tile_type& tile_type : device_ctx.physical_tile_types) {
337	        avail_tiles[&tile_type] = grid.num_instances(&tile_type, -1);
338	    }
339	
340	    //Sort so we allocate logical blocks with the fewest equivalent sites first (least flexible)
341	    std::vector<const t_logical_block_type*> logical_block_types;
342	    logical_block_types.reserve(device_ctx.logical_block_types.size());
343	    for (const t_logical_block_type& block_type : device_ctx.logical_block_types) {
344	        logical_block_types.push_back(&block_type);
345	    }
346	
347	    auto by_ascending_equiv_tiles = [](t_logical_block_type_ptr lhs, t_logical_block_type_ptr rhs) {
348	        return lhs->equivalent_tiles.size() < rhs->equivalent_tiles.size();
349	    };
350	    std::stable_sort(logical_block_types.begin(), logical_block_types.end(), by_ascending_equiv_tiles);
351	
352	    //Allocate logical blocks to available tiles
353	    for (const t_logical_block_type_ptr block_type : logical_block_types) {
354	        if (instance_counts.count(block_type)) {
355	            int required_blocks = instance_counts[block_type];
356	
357	            for (const t_physical_tile_type_ptr tile_type : block_type->equivalent_tiles) {
358	                if (avail_tiles[tile_type] >= required_blocks) {
359	                    avail_tiles[tile_type] -= required_blocks;
360	                    required_blocks = 0;
361	                } else {
362	                    required_blocks -= avail_tiles[tile_type];
363	                    avail_tiles[tile_type] = 0;
364	                }
365	
366	                if (required_blocks == 0) break;
367	            }
368	
369	            if (required_blocks > 0) {
370	                overused_resources.push_back(block_type);
371	            }
372	        }
373	    }
374	
375	    return overused_resources;
376	}
377	
378	static bool grid_satisfies_instance_counts(const DeviceGrid& grid, const std::map<t_logical_block_type_ptr, size_t>& instance_counts, float maximum_utilization) {
379	    // Are the resources satisfied?
380	    std::vector<t_logical_block_type_ptr> overused_resources = grid_overused_resources(grid, instance_counts);
381	
382	    if (!overused_resources.empty()) {
383	        return false;
384	    }
385	
386	    //Is the utilization below the maximum?
387	    float utilization = calculate_device_utilization(grid, instance_counts);
388	
389	    if (utilization > maximum_utilization) {
390	        return false;
391	    }
392	
393	    return true; //OK
394	}
395	
396	static DeviceGrid build_device_grid(const t_grid_def& grid_def,
397	                                    size_t grid_width,
398	                                    size_t grid_height,
399	                                    bool warn_out_of_range,
400	                                    const std::vector<t_logical_block_type_ptr>& limiting_resources) {
401	    if (grid_def.grid_type == e_grid_def_type::FIXED) {
402	        if (grid_def.width != int(grid_width) || grid_def.height != int(grid_height)) {
403	            VPR_FATAL_ERROR(VPR_ERROR_OTHER,
404	                            "Requested grid size (%zu%zu) does not match fixed device size (%dx%d)",
405	                            grid_width, grid_height, grid_def.width, grid_def.height);
406	        }
407	    }
408	
409	    const DeviceContext& device_ctx = g_vpr_ctx.device();
410	
411	    // Initialize the grid and each location priority based on available dies in the architecture file
412	    vtr::NdMatrix<t_grid_tile, 3> grid;
413	    vtr::NdMatrix<int, 3> grid_priorities;
414	    size_t num_layers = grid_def.layers.size();
415	    grid.resize({num_layers, grid_width, grid_height});
416	    //Track the current priority for each grid location
417	    // Note that we initialize it to the lowest (i.e. most negative) possible value, so
418	    // any user-specified priority will override the default empty grid
419	    grid_priorities.resize({num_layers, grid_width, grid_height}, std::numeric_limits<int>::lowest());
420	
421	    // Initialize the device to all empty blocks
422	    t_physical_tile_type_ptr empty_type = device_ctx.EMPTY_PHYSICAL_TILE_TYPE;
423	    VTR_ASSERT(empty_type != nullptr);
424	    for (size_t layer = 0; layer < num_layers; ++layer) {
425	        for (size_t x = 0; x < grid_width; ++x) {
426	            for (size_t y = 0; y < grid_height; ++y) {
427	                set_grid_block_type(std::numeric_limits<int>::lowest() + 1, //+1 so it overrides without warning
428	                                    empty_type,
429	                                    layer, x, y,
430	                                    grid, grid_priorities,
431	                                    /*meta=*/nullptr);
432	            }
433	        }
434	    }
435	
436	    vtr::FormulaParser p;
437	    std::set<t_physical_tile_type_ptr> seen_types;
438	
439	    for (size_t layer = 0; layer < num_layers; layer++) {
440	        const t_layer_def& layer_def = grid_def.layers[layer];
441	
442	        for (const t_grid_loc_def& grid_loc_def : layer_def.loc_defs) {
443	            // Fill in the block types according to the specification
444	            t_physical_tile_type_ptr type = find_tile_type_by_name(grid_loc_def.block_type, device_ctx.physical_tile_types);
445	
446	            if (!type) {
447	                VPR_FATAL_ERROR(VPR_ERROR_ARCH,
448	                                "Failed to find block type '%s' for grid location specification",
449	                                grid_loc_def.block_type.c_str());
450	            }
451	
452	            seen_types.insert(type);
453	
454	            vtr::t_formula_data vars;
455	            vars.set_var_value("W", grid_width);
456	            vars.set_var_value("H", grid_height);
457	            vars.set_var_value("w", type->width);
458	            vars.set_var_value("h", type->height);
459	
460	            //Load the x specification
461	            const t_grid_loc_spec& xspec = grid_loc_def.x;
462	
463	            VTR_ASSERT_MSG(!xspec.start_expr.empty(), "x start position must be specified");
464	            VTR_ASSERT_MSG(!xspec.end_expr.empty(), "x end position must be specified");
465	            VTR_ASSERT_MSG(!xspec.incr_expr.empty(), "x increment must be specified");
466	            VTR_ASSERT_MSG(!xspec.repeat_expr.empty(), "x repeat must be specified");
467	
468	            size_t startx = p.parse_formula(xspec.start_expr, vars);
469	            size_t endx = p.parse_formula(xspec.end_expr, vars);
470	            size_t incrx = p.parse_formula(xspec.incr_expr, vars);
471	            size_t repeatx = p.parse_formula(xspec.repeat_expr, vars);
472	
473	            // Load the y specification
474	            const t_grid_loc_spec& yspec = grid_loc_def.y;
475	
476	            VTR_ASSERT_MSG(!yspec.start_expr.empty(), "y start position must be specified");
477	            VTR_ASSERT_MSG(!yspec.end_expr.empty(), "y end position must be specified");
478	            VTR_ASSERT_MSG(!yspec.incr_expr.empty(), "y increment must be specified");
479	            VTR_ASSERT_MSG(!yspec.repeat_expr.empty(), "y repeat must be specified");
480	
481	            size_t starty = p.parse_formula(yspec.start_expr, vars);
482	            size_t endy = p.parse_formula(yspec.end_expr, vars);
483	            size_t incry = p.parse_formula(yspec.incr_expr, vars);
484	            size_t repeaty = p.parse_formula(yspec.repeat_expr, vars);
485	
486	            // Check start against the device dimensions
487	            // Start locations outside the device will never create block instances
488	            if (startx > grid_width - 1) {
489	                if (warn_out_of_range) {
490	                    VTR_LOG_WARN("Block type '%s' grid location specification startx (%s = %d) falls outside device horizontal range [%d,%d]\n",
491	                                 type->name.c_str(), xspec.start_expr.c_str(), startx, 0, grid_width - 1);
492	                }
493	                continue; //No instances will be created
494	            }
495	
496	            if (starty > grid_height - 1) {
497	                if (warn_out_of_range) {
498	                    VTR_LOG_WARN("Block type '%s' grid location specification starty (%s = %d) falls outside device vertical range [%d,%d]\n",
499	                                 type->name.c_str(), yspec.start_expr.c_str(), starty, 0, grid_height - 1);
500	                }
501	                continue; //No instances will be created
502	            }
503	
504	            // Check end against the device dimensions
505	            if (endx > grid_width - 1) {
506	                if (warn_out_of_range) {
507	                    VTR_LOG_WARN("Block type '%s' grid location specification endx (%s = %d) falls outside device horizontal range [%d,%d]\n",
508	                                 type->name.c_str(), xspec.end_expr.c_str(), endx, 0, grid_width - 1);
509	                }
510	            }
511	
512	            if (endy > grid_height - 1) {
513	                if (warn_out_of_range) {
514	                    VTR_LOG_WARN("Block type '%s' grid location specification endy (%s = %d) falls outside device vertical range [%d,%d]\n",
515	                                 type->name.c_str(), yspec.end_expr.c_str(), endy, 0, grid_height - 1);
516	                }
517	            }
518	
519	            // The end must fall after (or equal) to the start
520	            if (endx < startx) {
521	                VPR_FATAL_ERROR(VPR_ERROR_ARCH,
522	                                "Grid location specification endx (%s = %d) can not come before startx (%s = %d) for block type '%s'",
523	                                xspec.end_expr.c_str(), endx, xspec.start_expr.c_str(), startx, type->name.c_str());
524	            }
525	
526	            if (endy < starty) {
527	                VPR_FATAL_ERROR(VPR_ERROR_ARCH,
528	                                "Grid location specification endy (%s = %d) can not come before starty (%s = %d) for block type '%s'",
529	                                yspec.end_expr.c_str(), endy, yspec.start_expr.c_str(), starty, type->name.c_str());
530	            }
531	
532	            // The minimum increment is the block dimension
533	            VTR_ASSERT(type->width > 0);
534	            if (incrx < size_t(type->width)) {
535	                VPR_FATAL_ERROR(VPR_ERROR_ARCH,
536	                                "Grid location specification incrx for block type '%s' must be at least"
537	                                " block width (%d) to avoid overlapping instances (was %s = %d)",
538	                                type->name.c_str(), type->width, xspec.incr_expr.c_str(), incrx);
539	            }
540	
541	            VTR_ASSERT(type->height > 0);
542	            if (incry < size_t(type->height)) {
543	                VPR_FATAL_ERROR(VPR_ERROR_ARCH,
544	                                "Grid location specification incry for block type '%s' must be at least"
545	                                " block height (%d) to avoid overlapping instances (was %s = %d)",
546	                                type->name.c_str(), type->height, yspec.incr_expr.c_str(), incry);
547	            }
548	
549	            // The minimum repeat is the region dimension
550	            size_t region_width = endx - startx + 1; //+1 since start/end are both inclusive
551	            if (repeatx < region_width) {
552	                VPR_FATAL_ERROR(VPR_ERROR_ARCH,
553	                                "Grid location specification repeatx for block type '%s' must be at least"
554	                                " the region width (%d) to avoid overlapping instances (was %s = %d)",
555	                                type->name.c_str(), region_width, xspec.repeat_expr.c_str(), repeatx);
556	            }
557	
558	            size_t region_height = endy - starty + 1; //+1 since start/end are both inclusive
559	            if (repeaty < region_height) {
560	                VPR_FATAL_ERROR(VPR_ERROR_ARCH,
561	                                "Grid location specification repeaty for block type '%s' must be at least"
562	                                " the region height (%d) to avoid overlapping instances (was %s = %d)",
563	                                type->name.c_str(), region_height, xspec.repeat_expr.c_str(), repeaty);
564	            }
565	
566	            size_t x_end = 0;
567	            for (size_t kx = 0; x_end < grid_width; ++kx) {
568	                // Repeat in x direction
569	                size_t x_start = startx + kx * repeatx;
570	                x_end = endx + kx * repeatx;
571	
572	                size_t y_end = 0;
573	                for (size_t ky = 0; y_end < grid_height; ++ky) { // Repeat in y direction
574	                    size_t y_start = starty + ky * repeaty;
575	                    y_end = endy + ky * repeaty;
576	
577	                    size_t x_max = std::min(x_end, grid_width - 1);
578	                    size_t y_max = std::min(y_end, grid_height - 1);
579	
580	                    // Fill in the region
581	                    for (size_t x = x_start; x + (type->width - 1) <= x_max; x += incrx) {
582	                        for (size_t y = y_start; y + (type->height - 1) <= y_max; y += incry) {
583	                            set_grid_block_type(grid_loc_def.priority,
584	                                                type,
585	                                                layer, x, y,
586	                                                grid, grid_priorities,
587	                                                grid_loc_def.meta);
588	                        }
589	                    }
590	                }
591	            }
592	        }
593	    }
594	
595	    // Warn if any types were not specified in the grid layout
596	    for (const t_physical_tile_type& type : device_ctx.physical_tile_types) {
597	        if (&type == empty_type) continue; // Don't worry if empty hasn't been specified
598	
599	        if (!seen_types.count(&type)) {
600	            VTR_LOG_WARN("Block type '%s' was not specified in device grid layout\n",
601	                         type.name.c_str());
602	        }
603	    }
604	
605	    DeviceGrid device_grid(grid_def, std::move(grid), limiting_resources);
606	
607	    check_grid(device_grid);
608	
609	    return device_grid;
610	}
611	
612	static void set_grid_block_type(int priority,
613	                                const t_physical_tile_type* type,
614	                                size_t layer_num,
615	                                size_t x_root,
616	                                size_t y_root,
617	                                vtr::NdMatrix<t_grid_tile, 3>& grid,
618	                                vtr::NdMatrix<int, 3>& grid_priorities,
619	                                const t_metadata_dict* meta) {
620	    struct TypeLocation {
621	        TypeLocation(size_t x_val, size_t y_val, const t_physical_tile_type* type_val, int priority_val)
622	            : x(x_val)
623	            , y(y_val)
624	            , type(type_val)
625	            , priority(priority_val) {}
626	        size_t x;
627	        size_t y;
628	        const t_physical_tile_type* type;
629	        int priority;
630	
631	        bool operator<(const TypeLocation& rhs) const {
632	            return x < rhs.x || y < rhs.y || type < rhs.type;
633	        }
634	    };
635	
636	    //Collect locations effected by this block
637	    std::set<TypeLocation> target_locations;
638	    for (size_t x = x_root; x < x_root + type->width; ++x) {
639	        for (size_t y = y_root; y < y_root + type->height; ++y) {
640	            target_locations.insert(TypeLocation(x, y, grid[layer_num][x][y].type, grid_priorities[layer_num][x][y]));
641	        }
642	    }
643	
644	    //Record the highest priority of all effected locations
645	    auto iter = target_locations.begin();
646	    TypeLocation max_priority_type_loc = *iter;
647	    for (; iter != target_locations.end(); ++iter) {
648	        if (iter->priority > max_priority_type_loc.priority) {
649	            max_priority_type_loc = *iter;
650	        }
651	    }
652	
653	    if (priority < max_priority_type_loc.priority) {
654	        //Lower priority, do not override
655	#ifdef VERBOSE
656	        VTR_LOG("Not creating block '%s' at (%zu,%zu) since overlaps block '%s' at (%zu,%zu) with higher priority (%d > %d)\n",
657	                type->name, x_root, y_root, max_priority_type_loc.type->name, max_priority_type_loc.x, max_priority_type_loc.y,
658	                max_priority_type_loc.priority, priority);
659	#endif
660	        return;
661	    }
662	
663	    if (priority == max_priority_type_loc.priority) {
664	        //Ambiguous case where current grid block and new specification have equal priority
665	        //
666	        //We arbitrarily decide to take the 'last applied' wins approach, and warn the user
667	        //about the potential ambiguity
668	        VTR_LOG_WARN(
669	            "Ambiguous block type specification at grid location (%zu,%zu)."
670	            " Existing block type '%s' at (%zu,%zu) has the same priority (%d) as new overlapping type '%s'."
671	            " The last specification will apply.\n",
672	            x_root, y_root,
673	            max_priority_type_loc.type->name.c_str(), max_priority_type_loc.x, max_priority_type_loc.y,
674	            priority, type->name.c_str());
675	    }
676	
677	    // Mark all the grid tiles 'covered' by this block with the appropriate type
678	    // and width/height offsets
679	    std::set<TypeLocation> root_blocks_to_rip_up;
680	    DeviceContext& device_ctx = g_vpr_ctx.mutable_device();
681	    for (size_t x = x_root; x < x_root + type->width; ++x) {
682	        VTR_ASSERT(x < grid.end_index(1));
683	
684	        size_t x_offset = x - x_root;
685	        for (size_t y = y_root; y < y_root + type->height; ++y) {
686	            VTR_ASSERT(y < grid.end_index(2));
687	            size_t y_offset = y - y_root;
688	
689	            t_grid_tile& grid_tile = grid[layer_num][x][y];
690	            VTR_ASSERT(grid_priorities[layer_num][x][y] <= priority);
691	
692	            if (grid_tile.type != nullptr
693	                && grid_tile.type != device_ctx.EMPTY_PHYSICAL_TILE_TYPE) {
694	                //We are overriding a non-empty block, we need to be careful
695	                //to ensure we remove any blocks which will be invalidated when we
696	                //overwrite part of their locations
697	
698	                size_t orig_root_x = x - grid[layer_num][x][y].width_offset;
699	                size_t orig_root_y = y - grid[layer_num][x][y].height_offset;
700	
701	                root_blocks_to_rip_up.insert(TypeLocation(orig_root_x,
702	                                                          orig_root_y,
703	                                                          grid[layer_num][x][y].type,
704	                                                          grid_priorities[layer_num][x][y]));
705	            }
706	
707	            grid[layer_num][x][y].type = type;
708	            grid[layer_num][x][y].width_offset = x_offset;
709	            grid[layer_num][x][y].height_offset = y_offset;
710	            grid[layer_num][x][y].meta = meta;
711	
712	            grid_priorities[layer_num][x][y] = priority;
713	        }
714	    }
715	
716	    // Rip-up any invalidated blocks
717	    for (const TypeLocation& invalidated_root : root_blocks_to_rip_up) {
718	        // Mark all the grid locations used by this root block as empty
719	        for (size_t x = invalidated_root.x; x < invalidated_root.x + invalidated_root.type->width; ++x) {
720	            int x_offset = x - invalidated_root.x;
721	            for (size_t y = invalidated_root.y; y < invalidated_root.y + invalidated_root.type->height; ++y) {
722	                int y_offset = y - invalidated_root.y;
723	
724	                if (grid[layer_num][x][y].type == invalidated_root.type
725	                    && grid[layer_num][x][y].width_offset == x_offset
726	                    && grid[layer_num][x][y].height_offset == y_offset) {
727	                    //This is a left-over invalidated block, mark as empty
728	                    // Note: that we explicitly check the type and offsets, since the original block
729	                    //       may have been completely overwritten, and we don't want to change anything
730	                    //       in that case
731	                    VTR_ASSERT(device_ctx.EMPTY_PHYSICAL_TILE_TYPE->width == 1);
732	                    VTR_ASSERT(device_ctx.EMPTY_PHYSICAL_TILE_TYPE->height == 1);
733	
734	#ifdef VERBOSE
735	                    VTR_LOG("Ripping up block '%s' at (%d,%d) offset (%d,%d). Overlapped by '%s' at (%d,%d)\n",
736	                            invalidated_root.type->name, invalidated_root.x, invalidated_root.y,
737	                            x_offset, y_offset,
738	                            type->name, x_root, y_root);
739	#endif
740	
741	                    grid[layer_num][x][y].type = device_ctx.EMPTY_PHYSICAL_TILE_TYPE;
742	                    grid[layer_num][x][y].width_offset = 0;
743	                    grid[layer_num][x][y].height_offset = 0;
744	
745	                    grid_priorities[layer_num][x][y] = std::numeric_limits<int>::lowest();
746	                }
747	            }
748	        }
749	    }
750	}
751	
752	static void check_grid(const DeviceGrid& grid) {
753	    for (const t_physical_tile_loc tile_loc : grid.all_locations()) {
754	        const t_physical_tile_type_ptr type = grid.get_physical_type(tile_loc);
755	        int width_offset = grid.get_width_offset(tile_loc);
756	        int height_offset = grid.get_height_offset(tile_loc);
757	        if (nullptr == type) {
758	            VPR_FATAL_ERROR(VPR_ERROR_OTHER, "Grid Location (%d,%d,%d) has no type.\n", tile_loc.layer_num, tile_loc.x, tile_loc.y);
759	        }
760	
761	        if ((grid.get_width_offset(tile_loc) < 0) || (grid.get_width_offset(tile_loc) >= type->width)) {
762	            VPR_FATAL_ERROR(VPR_ERROR_OTHER, "Grid Location (%d,%d,%d) has invalid width offset (%d).\n",
763	                            tile_loc.layer_num, tile_loc.x, tile_loc.y,
764	                            width_offset);
765	        }
766	        if ((grid.get_height_offset(tile_loc) < 0) || (grid.get_height_offset(tile_loc) >= type->height)) {
767	            VPR_FATAL_ERROR(VPR_ERROR_OTHER, "Grid Location (%d,%d,%d) has invalid height offset (%d).\n",
768	                            tile_loc.layer_num, tile_loc.x, tile_loc.y,
769	                            height_offset);
770	        }
771	
772	        // Verify that type and width/height offsets are correct (e.g. for dimension > 1 blocks)
773	        if (grid.get_width_offset(tile_loc) == 0 && grid.get_height_offset(tile_loc) == 0) {
774	            // From the root block check that all other blocks are correct
775	            for (int x = tile_loc.x; x < tile_loc.x + type->width; ++x) {
776	                int x_offset = x - tile_loc.x;
777	                for (int y = tile_loc.y; y < tile_loc.y + type->height; ++y) {
778	                    int y_offset = y - tile_loc.y;
779	                    const t_physical_tile_loc tile_loc_offset(x, y, tile_loc.layer_num);
780	                    const t_physical_tile_type_ptr tile_type = grid.get_physical_type(tile_loc_offset);
781	                    int tile_width_offset = grid.get_width_offset(tile_loc_offset);
782	                    int tile_height_offset = grid.get_height_offset(tile_loc_offset);
783	                    if (tile_type != type) {
784	                        VPR_FATAL_ERROR(VPR_ERROR_OTHER,
785	                                        "Grid Location (%d,%d,%d) should have type '%s' (based on root location) but has type '%s'\n",
786	                                        tile_loc.layer_num, tile_loc.x, tile_loc.y, type->name.c_str(), type->name.c_str());
787	                    }
788	
789	                    if (tile_width_offset != x_offset) {
790	                        VPR_FATAL_ERROR(VPR_ERROR_OTHER,
791	                                        "Grid Location (%d,%d,%d) of type '%s' should have width offset '%d' (based on root location) but has '%d'\n",
792	                                        tile_loc.layer_num, tile_loc.x, tile_loc.y, type->name.c_str(), x_offset, tile_width_offset);
793	                    }
794	
795	                    if (tile_height_offset != y_offset) {
796	                        VPR_FATAL_ERROR(VPR_ERROR_OTHER,
797	                                        "Grid Location (%d,%d,%d)  of type '%s' should have height offset '%d' (based on root location) but has '%d'\n",
798	                                        tile_loc.layer_num, tile_loc.x, tile_loc.y, type->name.c_str(), y_offset, tile_height_offset);
799	                    }
800	                }
801	            }
802	        }
803	    }
804	}
805	
806	size_t count_grid_tiles(const DeviceGrid& grid) {
807	    return grid.get_num_layers() * grid.width() * grid.height();
808	}
809	
810	void report_device_grid_stats(const DeviceGrid& grid) {
811	    size_t num_grid_tiles = count_grid_tiles(grid);
812	    VTR_LOG("FPGA sized to %zu x %zu: %zu grid tiles (%s)\n",
813	            grid.width(), grid.height(), num_grid_tiles, grid.name().c_str());
814	}
